import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{n as i,t as a}from"./chunks/template-generator-advanced.CleIDHrl.js";import{n as o,t as s}from"./chunks/gradle-prompt.DgUqZl-T.js";const c=JSON.parse(`{"title":"Creando un Proyecto","description":"Una guía paso a paso sobre como crear un proyecto de mod usando el generador de plantillas de mods de Fabric.","frontmatter":{"title":"Creando un Proyecto","description":"Una guía paso a paso sobre como crear un proyecto de mod usando el generador de plantillas de mods de Fabric.","authors":["IMB11"],"files":[]},"headers":[],"relativePath":"es_es/1.21.1/develop/getting-started/creating-a-project.md","filePath":"versions/1.21.1/translated/es_es/develop/getting-started/creating-a-project.md","lastUpdated":1761424914000}`);var l={name:`es_es/1.21.1/develop/getting-started/creating-a-project.md`};function u(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Creando un Proyecto <a class="header-anchor" href="#h1" aria-label="Permalink to “Creando un Proyecto”">​</a></h1><p>Fabric provee una manera fácil de crear un nuevo proyecto de mod usando el Generador de Plantillas de Mods de Fabric - si quieres, puedes crear un nuevo proyecto manualmelnte usando el repositorio del mod de ejemplo, deberías visitar la sección de <a href="#manual-project-creation">Creación Manual de Proyectos</a>.</p><h2 id="generando-un-proyecto" tabindex="-1">Generando un Proyecto <a class="header-anchor" href="#generando-un-proyecto" aria-label="Permalink to “Generando un Proyecto”">​</a></h2><p>Puedes usar el <a href="https://fabricmc.net/develop/template/" target="_blank" rel="noreferrer">Generador de Plantillas de Mods de Fabric</a> para generar un nuevo proyecto para tu mod - deberías llenar los campos requeridos, como el nombre del paquete y el nombre del mod, y la versión de Minecraft para la cual quieres desarrollar.</p><p><img src="/assets/develop/getting-started/template-generator.png" alt="Vista previa del generador" loading="lazy"></p><p>Si quieres usar Kotlin, o quieres agregar generadores de datos, puedes seleccionar las opciones correspondientes en la sección de <code>Advanced Options</code> (Opciones Avanzadas).</p><p><img src="/assets/develop/getting-started/template-generator-advanced.png" alt="Sección de Opciones Avanzadas" loading="lazy"></p><p>Una vez llenados los campos requeridos, haz clic en el botón de <code>Generate</code> (Generar), y el generador creará un nuevo proyecto para ti en la forma de archivo zip.</p><p>Deberías extraer este archivo zip en un lugar de tu elección, y luego abre el folder extraído en IntelliJ IDEA:</p><p><img src="/assets/develop/getting-started/open-project.png" alt="Sugerencia de Proyecto Abierto" loading="lazy"></p><h2 id="importando-el-proyecto" tabindex="-1">Importando el Proyecto <a class="header-anchor" href="#importando-el-proyecto" aria-label="Permalink to “Importando el Proyecto”">​</a></h2><p>Una vez que has abierto el proyecto en IntelliJ IDEA, el IDEA debería automáticamente cargar las configuraciones de Gradle y realizar las tareas de configuración necesarias.</p><p>Si recibes una notificación que habla sobre un <em>script</em> de Gradle, deberías hacer clic en el botón de <code>Import Gradle Project</code> (Importar Proyecto de Gradle):</p><p><img src="/assets/develop/getting-started/gradle-prompt.png" alt="Sugerencia de Gradle" loading="lazy"></p><p>Una vez que el proyecto ha sido importado, deberías ver los archivos del proyecto en el explorador del proyecto, y deberías poder empezar a desarrollar tu mod.</p><h2 id="creacion-manual-de-proyectos" tabindex="-1">Creación Manual de Proyectos <a class="header-anchor" href="#creacion-manual-de-proyectos" aria-label="Permalink to “Creación Manual de Proyectos”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Necesitarás tener instalado <a href="https://git-scm.com/" target="_blank" rel="noreferrer">Git</a> para clonar el repositorio del mod de ejemplo.</p></div><p>Si no puedes usar el Generador de Plantillas de Mods de Fabric, puedes crear un nuevo proyecto siguiendo los siguientes pasos.</p><p>Primero, clona el repositorio del mod de ejemplo usando Git:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/FabricMC/fabric-example-mod/</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-mod-project</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Esto clonará el repositorio a un nuevo folder llamado <code>my-mod-project</code>.</p><p>Después, deberías eliminar el folder de <code>.git</code> del repositorio clonado, y luego abre el proyecto en IntelliJ IDEA. Si el folder de <code>.git</code> no aparece, deberías habilitar la visualización de archivos ocultos en tu administrador de archivos.</p><p>Una vez que has abierto el proyecto en IntelliJ IDEA, el IDEA debería automáticamente cargar las configuraciones de Gradle y realizar las tareas de configuración necesarias.</p><p>Nuevamente, como ya hemos dicho, si recibes una notificación que habla sobre un <em>script</em> de Gradle, deberías hacer clic en el botón de <code>Import Gradle Project</code> (Importar Proyecto de Gradle).</p><h3 id="modificando-la-plantilla" tabindex="-1">Modificando La Plantilla <a class="header-anchor" href="#modificando-la-plantilla" aria-label="Permalink to “Modificando La Plantilla”">​</a></h3><p>Una vez que el proyecto ha sido importado, deberías poder modificar los detalles del proyecto para que encajen con los detalles de tu mod:</p><ul><li>Modifica el archivo de <code>gradle.properties</code> de tu proyecto para cambiar las propiedades de <code>maven_group</code> (grupo de maven) y <code>archive_base_name</code> (nombre base del archivo) para que sean los de tu mod.</li><li>Modifica el archivo de <code>fabric.mod.json</code> para cambiar las propiedades de <code>id</code>, <code>name</code>, y <code>description</code> para que sean los de tu mod.</li><li>Asegúrate de actualizar las versiones de Minecraft, los mapeos, el cargador de Fabric y Loom - todos ellos pueden ser consultados en <a href="https://fabricmc.net/develop/" target="_blank" rel="noreferrer">https://fabricmc.net/develop/</a> - para tener las versiones deseadas.</li></ul><p>Obviamente también puedes cambiar el nombre del paquete y la clase principal para que sean las de tu mod.</p>`,28)]])}var d=r(l,[[`render`,u]]);export{c as __pageData,d as default};